import numpy as np

def color_jitter(
    image: np.ndarray,
    brightness: float = 0.2,
    contrast: float = 0.2,
    saturation: float = 0.2,
    seed: int = None
) -> np.ndarray:
    rng = np.random.default_rng(seed)
    img = image.astype(np.float64).copy()

    def apply_brightness(x):
        factor = rng.uniform(1 - brightness, 1 + brightness)
        return x * factor

    def apply_contrast(x):
        factor = rng.uniform(1 - contrast, 1 + contrast)
        mean = x.mean()
        return mean + factor * (x - mean)

    def apply_saturation(x):
        factor = rng.uniform(1 - saturation, 1 + saturation)
        gray = (0.299 * x[:, :, 0] + 0.587 * x[:, :, 1] + 0.114 * x[:, :, 2])[:, :, np.newaxis]
        return gray + factor * (x - gray)

    transforms = [apply_brightness, apply_contrast, apply_saturation]
    order = rng.permutation(3)
    for idx in order:
        img = transforms[idx](img)

    return np.clip(img, 0.0, 1.0)
